"use strict";(self.webpackChunkai_qa_learning_site=self.webpackChunkai_qa_learning_site||[]).push([["173"],{9986(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/04/10/day1-llm-basics","metadata":{"permalink":"/ai-qa-learning-site/blog/2026/04/10/day1-llm-basics","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2026-04-10-day1-llm-basics.md","source":"@site/blog/2026-04-10-day1-llm-basics.md","title":"\u6BCF\u65E5 AI \u5B66\u4E60\u7B14\u8BB0 Day 1\uFF1ALLM \u7684\u524D\u4E16\u4ECA\u751F","description":"\u5B66\u4E60\u76EE\u6807\uFF1A\u5EFA\u7ACB\u4E00\u5957\u201C\u80FD\u7528\u4E8E\u6D4B\u8BD5\u8BBE\u8BA1\u201D\u7684\u5FC3\u667A\u6A21\u578B\uFF1ALLM \u8F93\u51FA\u4E3A\u4EC0\u4E48\u4F1A\u53D8\uFF1F\u54EA\u4E9B\u73AF\u8282\u5F15\u5165\u4E0D\u786E\u5B9A\u6027\uFF1FQA \u600E\u4E48\u628A\u5B83\u62C6\u6210\u53EF\u6D4B\u7684\u7EC4\u4EF6\u4E0E\u53EF\u63A7\u7684\u53D8\u91CF\uFF1F","date":"2026-04-10T00:00:00.000Z","tags":[{"inline":false,"label":"AI \u5B66\u4E60\u7B14\u8BB0","permalink":"/ai-qa-learning-site/blog/tags/learning-notes","description":"\u4E2A\u4EBA AI \u5B66\u4E60\u8FC7\u7A0B\u4E2D\u7684\u7B14\u8BB0\u4E0E\u5B9E\u8DF5\u8BB0\u5F55"},{"inline":false,"label":"AI","permalink":"/ai-qa-learning-site/blog/tags/ai","description":"AI / \u5927\u6A21\u578B\u4E0E\u667A\u80FD\u4F53\u76F8\u5173\u5B9E\u8DF5"},{"inline":false,"label":"QA","permalink":"/ai-qa-learning-site/blog/tags/qa","description":"\u8D28\u91CF\u4FDD\u969C\u4E0E\u6D4B\u8BD5\u5DE5\u7A0B\u5316"},{"inline":false,"label":"LLM","permalink":"/ai-qa-learning-site/blog/tags/llm","description":"\u5927\u8BED\u8A00\u6A21\u578B\uFF08LLM\uFF09\u539F\u7406\u3001\u80FD\u529B\u8BC4\u6D4B\u4E0E\u5DE5\u7A0B\u5316\u5B9E\u8DF5"}],"readingTime":5.99,"hasTruncateMarker":true,"authors":[{"name":"Eileen","title":"QA / \u6D4B\u8BD5\u5F00\u53D1","page":{"permalink":"/ai-qa-learning-site/blog/authors/eileen"},"key":"eileen"}],"frontMatter":{"title":"\u6BCF\u65E5 AI \u5B66\u4E60\u7B14\u8BB0 Day 1\uFF1ALLM \u7684\u524D\u4E16\u4ECA\u751F","authors":["eileen"],"tags":["learning-notes","AI","QA","LLM"],"date":"2026-04-10T00:00:00.000Z"},"unlisted":false,"nextItem":{"title":"GitHub Trending AI \u9879\u76EE\u6DF1\u5EA6\u7814\u7A76\uFF1A\u8D4B\u80FD QA \u7684\u5DE5\u7A0B\u5316\u673A\u9047","permalink":"/ai-qa-learning-site/blog/2026/04/10/github-trending-ai-qa"}},"content":"> \u5B66\u4E60\u76EE\u6807\uFF1A\u5EFA\u7ACB\u4E00\u5957\u201C\u80FD\u7528\u4E8E\u6D4B\u8BD5\u8BBE\u8BA1\u201D\u7684\u5FC3\u667A\u6A21\u578B\uFF1ALLM \u8F93\u51FA\u4E3A\u4EC0\u4E48\u4F1A\u53D8\uFF1F\u54EA\u4E9B\u73AF\u8282\u5F15\u5165\u4E0D\u786E\u5B9A\u6027\uFF1FQA \u600E\u4E48\u628A\u5B83\u62C6\u6210\u53EF\u6D4B\u7684\u7EC4\u4EF6\u4E0E\u53EF\u63A7\u7684\u53D8\u91CF\uFF1F\\n\\n{/* truncate */}\\n\\n## 1) \u6838\u5FC3\u7406\u8BBA\u77E5\u8BC6\u8BB2\u89E3\\n\\n### 1.1 Transformer\uFF1ALLM \u7684\u201C\u57FA\u7840\u53D1\u52A8\u673A\u201D\\nLLM \u7684\u6838\u5FC3\u662F **Transformer**\uFF0C\u5B83\u89E3\u51B3\u4E86\u4F20\u7EDF RNN \u5728\u957F\u5E8F\u5217\u4E0A\u96BE\u4EE5\u5E76\u884C\u3001\u96BE\u4EE5\u6355\u6349\u8FDC\u8DDD\u79BB\u4F9D\u8D56\u7684\u95EE\u9898\u3002\\n\\n\u5173\u952E\u70B9\uFF08\u9762\u5411\u6D4B\u8BD5/\u5DE5\u7A0B\u7406\u89E3\u5373\u53EF\uFF09\uFF1A\\n- **Token**\uFF1A\u6587\u672C\u88AB\u5207\u6210 token\uFF1B\u6D4B\u8BD5\u65F6\u8981\u5173\u6CE8 tokenization \u5BFC\u81F4\u7684\u8FB9\u754C\u95EE\u9898\uFF08\u4E2D\u82F1\u6587\u3001\u7279\u6B8A\u7B26\u53F7\u3001\u7A7A\u683C\u3001\u6362\u884C\u3001emoji \u7B49\uFF09\u3002\\n- **Self-Attention**\uFF1A\u6A21\u578B\u4F1A\u5BF9\u4E0A\u4E0B\u6587\u91CC\u54EA\u4E9B token \u66F4\u201C\u76F8\u5173\u201D\u5206\u914D\u66F4\u9AD8\u6743\u91CD\u3002\\n  - QA \u542F\u53D1\uFF1A\u5F53\u4F60\u53D1\u73B0\u201C\u6A21\u578B\u5FFD\u7565\u5173\u952E\u4FE1\u606F\u201D\uFF0C\u5F80\u5F80\u662F attention \u6CA1\u201C\u76EF\u4F4F\u201D\u4F60\u7684\u5173\u952E\u5B57\u6BB5\uFF08\u4F8B\u5982\u6743\u9650\u3001\u79DF\u6237\u3001\u65F6\u95F4\u8303\u56F4\uFF09\u3002\\n- **\u4F4D\u7F6E\u7F16\u7801**\uFF1ATransformer \u672C\u8EAB\u4E0D\u611F\u77E5\u987A\u5E8F\uFF0C\u9700\u8981\u989D\u5916\u6CE8\u5165\u4F4D\u7F6E\u4FE1\u606F\u3002\\n  - QA \u542F\u53D1\uFF1A\u540C\u4E00\u53E5\u8BDD\u6362\u884C/\u6362\u987A\u5E8F\u53EF\u80FD\u5F15\u53D1\u7ED3\u679C\u53D8\u5316\uFF0C\u8FD9\u662F\u53EF\u6D4B\u7684\u201C\u6270\u52A8\u7EF4\u5EA6\u201D\u3002\\n\\n### 1.2 \u9884\u8BAD\u7EC3\uFF08Pre-training\uFF09\uFF1A\u6A21\u578B\u7684\u201C\u901A\u8BC6\u8BED\u611F\u201D\u4ECE\u54EA\u6765\\n\u9884\u8BAD\u7EC3\u901A\u5E38\u662F\u5927\u89C4\u6A21\u8BED\u6599\u4E0A\u7684\u81EA\u76D1\u7763\u5B66\u4E60\uFF08\u5178\u578B\u76EE\u6807\uFF1A\u9884\u6D4B\u4E0B\u4E00\u4E2A token\uFF09\u3002\\n- \u7ED3\u679C\uFF1A\u6A21\u578B\u83B7\u5F97\u8BED\u8A00\u89C4\u5F8B\u3001\u5E38\u8BC6\u3001\u9886\u57DF\u77E5\u8BC6\u7684\u201C\u7C97\u80FD\u529B\u201D\u3002\\n- \u98CE\u9669\uFF1A\\n  - **\u77E5\u8BC6\u5E7B\u89C9**\uFF1A\u6A21\u578B\u4F1A\u751F\u6210\u770B\u4F3C\u5408\u7406\u4F46\u4E0D\u771F\u5B9E\u7684\u5185\u5BB9\u3002\\n  - **\u65F6\u95F4\u6EDE\u540E**\uFF1A\u8BAD\u7EC3\u8BED\u6599\u622A\u6B62\u65F6\u95F4\u5BFC\u81F4\u201C\u65B0\u77E5\u8BC6\u7F3A\u5931\u201D\u3002\\n\\n### 1.3 SFT\uFF08\u76D1\u7763\u5FAE\u8C03\uFF09\uFF1A\u8BA9\u6A21\u578B\u5B66\u4F1A\u201C\u6309\u6307\u4EE4\u505A\u4E8B\u201D\\nSFT \u7528\u9AD8\u8D28\u91CF\u6807\u6CE8\u6570\u636E\uFF08\u6307\u4EE4-\u56DE\u7B54\uFF09\u8BAD\u7EC3\uFF0C\u8BA9\u6A21\u578B\u66F4\u50CF\u201C\u52A9\u624B\u201D\u3002\\n- QA \u5173\u6CE8\u70B9\uFF1A\\n  - **\u9075\u5FAA\u6307\u4EE4**\uFF08Instruction Following\uFF09\u663E\u8457\u589E\u5F3A\uFF0C\u4F46\u4E5F\u4F1A\u5F15\u5165\u201C\u6A21\u677F\u5316\u56DE\u7B54\u201D\u3002\\n  - \u5BF9\u7279\u5B9A\u683C\u5F0F\uFF08JSON\u3001\u8868\u683C\u3001\u4EE3\u7801\uFF09\u66F4\u53CB\u597D\uFF1A\u8FD9\u5BF9\u201C\u53EF\u9A8C\u8BC1\u6027\u201D\u975E\u5E38\u5173\u952E\u3002\\n\\n### 1.4 RLHF\uFF1A\u7528\u4EBA\u7C7B\u504F\u597D\u628A\u6A21\u578B\u201C\u62C9\u5230\u5BF9\u7684\u65B9\u5411\u201D\\nRLHF\uFF08Reinforcement Learning from Human Feedback\uFF09\u6838\u5FC3\u601D\u8DEF\uFF1A\\n- \u4EBA\u7C7B\u5BF9\u591A\u4E2A\u5019\u9009\u56DE\u7B54\u505A\u504F\u597D\u6392\u5E8F\\n- \u8BAD\u7EC3 Reward Model\\n- \u7528\u5F3A\u5316\u5B66\u4E60\u4F18\u5316\u751F\u6210\u7B56\u7565\\n\\nQA \u89C6\u89D2\u7684\u201C\u526F\u4F5C\u7528/\u6D4B\u8BD5\u70B9\u201D\uFF1A\\n- \u6A21\u578B\u66F4\u201C\u5B89\u5168/\u793C\u8C8C\u201D\uFF0C\u4F46\u53EF\u80FD\u51FA\u73B0 **\u8FC7\u5EA6\u62D2\u7B54**\uFF08\u5BF9\u6B63\u5E38\u8BF7\u6C42\u4E5F\u62D2\u7EDD\uFF09\u3002\\n- \u5BF9\u540C\u4E00\u95EE\u9898\u53EF\u80FD\u66F4\u503E\u5411\u7ED9\u201C\u4E2D\u5EB8\u4F46\u5B89\u5168\u201D\u7684\u7B54\u6848\uFF0C\u5BFC\u81F4\u4FE1\u606F\u5BC6\u5EA6\u4E0B\u964D\u3002\\n\\n### 1.5 Temperature / Top-p\uFF1A\u4F60\u80FD\u76F4\u63A5\u63A7\u5236\u7684\u201C\u968F\u673A\u6027\u65CB\u94AE\u201D\\n- **Temperature**\uFF1A\u8D8A\u9AD8\u8D8A\u53D1\u6563\u3001\u8D8A\u6709\u521B\u9020\u6027\uFF1B\u8D8A\u4F4E\u8D8A\u7A33\u5B9A\u3001\u66F4\u50CF\u68C0\u7D22\u5F0F\u56DE\u7B54\u3002\\n- **Top-p\uFF08nucleus sampling\uFF09**\uFF1A\u4ECE\u7D2F\u8BA1\u6982\u7387\u8FBE\u5230 p \u7684\u5019\u9009 token \u96C6\u5408\u91CC\u91C7\u6837\uFF1Bp \u8D8A\u5C0F\u8D8A\u4FDD\u5B88\u3002\\n\\nQA \u7ED3\u8BBA\uFF1A\\n- \u8FD9\u4E24\u4E2A\u53C2\u6570\u662F\u4F60\u505A\u7A33\u5B9A\u6027/\u56DE\u5F52\u6D4B\u8BD5\u65F6\u5FC5\u987B\u201C\u56FA\u5B9A\u201D\u7684\u53D8\u91CF\u4E4B\u4E00\u3002\\n- \u82E5\u7EBF\u4E0A\u4EA7\u54C1\u5141\u8BB8\u7528\u6237\u914D\u7F6E\u5B83\u4EEC\uFF0C\u9700\u8981\u660E\u786E\uFF1A**\u54EA\u4E9B\u573A\u666F\u5141\u8BB8\u53D1\u6563\uFF08\u521B\u610F\uFF09\uFF0C\u54EA\u4E9B\u5FC5\u987B\u7A33\u5B9A\uFF08\u751F\u6210\u914D\u7F6E/\u7528\u4F8B/\u4EE3\u7801\uFF09**\u3002\\n\\n---\\n\\n## 2) \u7ED3\u5408\u6D4B\u5F00\u89C6\u89D2\u7684\u5DE5\u7A0B\u5B9E\u8DF5\uFF08\u542B Python/Go \u793A\u4F8B\uFF09\\n\\n\u4ECA\u5929\u7684\u5B9E\u8DF5\u76EE\u6807\uFF1A\\n1) \u7528\u540C\u4E00 Prompt\uFF0C\u5728\u4E0D\u540C Temperature / Top-p \u4E0B\u91C7\u6837\u591A\u6B21\\n2) \u8BA1\u7B97\u201C\u6CE2\u52A8\u6027\u201D\u6307\u6807\uFF0C\u5F62\u6210\u53EF\u7EB3\u5165 CI \u7684\u81EA\u52A8\u5316\u8BC4\u6D4B\\n\\n> \u8BF4\u660E\uFF1A\u4E0B\u9762\u7528\u201C\u7C7B OpenAI Chat Completions\u201D\u98CE\u683C\u793A\u4F8B\u3002\u4F60\u5728\u4F01\u4E1A\u5185\u90E8/\u706B\u5C71\u5F15\u64CE/\u8C46\u5305\u7B49\u5E73\u53F0\uFF0C\u53EA\u9700\u8981\u66FF\u6362 endpoint\u3001\u9274\u6743 header\u3001request body \u5B57\u6BB5\u5373\u53EF\u3002\\n\\n### 2.1 Python\uFF1A\u53C2\u6570\u6270\u52A8\u5B9E\u9A8C + \u7A33\u5B9A\u6027\u5EA6\u91CF\uFF08Jaccard + \u7ED3\u6784\u6821\u9A8C\uFF09\\n\\n```python\\nimport os\\nimport json\\nimport time\\nimport requests\\nfrom typing import List\\n\\nAPI_URL = os.getenv(\\"LLM_API_URL\\")\\nAPI_KEY = os.getenv(\\"LLM_API_KEY\\")\\n\\nPROMPT = \\"\\"\\"\u4F60\u662F\u4E00\u540D\u6D4B\u8BD5\u5F00\u53D1\u5DE5\u7A0B\u5E08\u3002\u8BF7\u7528 JSON \u8F93\u51FA 3 \u6761 ArkClaw \u63A5\u53E3\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u5B57\u6BB5\u5305\u542B\uFF1Aid, title, steps, expected\u3002\\"\\"\\"\\n\\n\\ndef call_llm(temp: float, top_p: float) -> str:\\n    payload = {\\n        \\"model\\": \\"your-model\\",\\n        \\"messages\\": [\\n            {\\"role\\": \\"system\\", \\"content\\": \\"You are a helpful assistant.\\"},\\n            {\\"role\\": \\"user\\", \\"content\\": PROMPT},\\n        ],\\n        \\"temperature\\": temp,\\n        \\"top_p\\": top_p,\\n    }\\n\\n    r = requests.post(\\n        API_URL,\\n        headers={\\"Authorization\\": f\\"Bearer {API_KEY}\\", \\"Content-Type\\": \\"application/json\\"},\\n        data=json.dumps(payload),\\n        timeout=60,\\n    )\\n    r.raise_for_status()\\n    data = r.json()\\n    return data[\\"choices\\"][0][\\"message\\"][\\"content\\"]\\n\\n\\ndef jaccard(a: str, b: str) -> float:\\n    sa, sb = set(a.split()), set(b.split())\\n    if not sa and not sb:\\n        return 1.0\\n    return len(sa & sb) / max(1, len(sa | sb))\\n\\n\\ndef run_experiment(temp: float, top_p: float, n: int = 5) -> List[str]:\\n    outs = []\\n    for _ in range(n):\\n        outs.append(call_llm(temp, top_p))\\n        time.sleep(0.2)\\n    return outs\\n\\n\\ndef try_parse_json(text: str) -> bool:\\n    try:\\n        json.loads(text)\\n        return True\\n    except Exception:\\n        return False\\n\\n\\nif __name__ == \\"__main__\\":\\n    for (temp, top_p) in [(0.0, 1.0), (0.2, 0.9), (0.8, 0.95)]:\\n        outs = run_experiment(temp, top_p, n=5)\\n        # 1) \u7ED3\u6784\u53EF\u89E3\u6790\u7387\\n        ok_rate = sum(try_parse_json(x) for x in outs) / len(outs)\\n        # 2) \u8F93\u51FA\u76F8\u4F3C\u5EA6\uFF08\u4E0E\u7B2C\u4E00\u6B21\u5BF9\u6BD4\uFF09\\n        base = outs[0]\\n        sim = sum(jaccard(base, x) for x in outs[1:]) / max(1, len(outs) - 1)\\n\\n        print(f\\"temp={temp}, top_p={top_p} -> json_ok_rate={ok_rate:.2f}, avg_jaccard={sim:.2f}\\")\\n```\\n\\nQA \u4F60\u53EF\u4EE5\u600E\u4E48\u7528\uFF1A\\n- **json_ok_rate**\uFF1A\u8861\u91CF\u201C\u7ED3\u6784\u5316\u8F93\u51FA\u9075\u5FAA\u5EA6\u201D\uFF08\u975E\u5E38\u9002\u5408\u4F60\u4EEC\u505A\u81EA\u52A8\u5316\u3001\u7528\u4F8B\u751F\u6210\u3001\u914D\u7F6E\u751F\u6210\u573A\u666F\uFF09\u3002\\n- **avg_jaccard**\uFF1A\u8861\u91CF\u201C\u6587\u672C\u7A33\u5B9A\u6027\u201D\uFF08\u9002\u5408\u505A\u56DE\u5F52\u9608\u503C\uFF09\u3002\\n\\n### 2.2 Go\uFF1A\u505A\u6210\u53EF\u8DD1\u5728 CI \u7684\u201CLLM \u53EF\u6D4B\u6027\u63A2\u9488\u201D\\n\\n```go\\npackage llmprobe\\n\\nimport (\\n\\t\\"bytes\\"\\n\\t\\"encoding/json\\"\\n\\t\\"fmt\\"\\n\\t\\"net/http\\"\\n\\t\\"time\\"\\n)\\n\\ntype Req struct {\\n\\tModel       string        `json:\\"model\\"`\\n\\tMessages    []Message     `json:\\"messages\\"`\\n\\tTemperature float64       `json:\\"temperature\\"`\\n\\tTopP        float64       `json:\\"top_p\\"`\\n}\\n\\ntype Message struct {\\n\\tRole    string `json:\\"role\\"`\\n\\tContent string `json:\\"content\\"`\\n}\\n\\ntype Resp struct {\\n\\tChoices []struct {\\n\\t\\tMessage struct {\\n\\t\\t\\tContent string `json:\\"content\\"`\\n\\t\\t} `json:\\"message\\"`\\n\\t} `json:\\"choices\\"`\\n}\\n\\nfunc Call(apiURL, apiKey string, temp, topP float64, prompt string) (string, error) {\\n\\treqBody := Req{\\n\\t\\tModel: \\"your-model\\",\\n\\t\\tMessages: []Message{\\n\\t\\t\\t{Role: \\"system\\", Content: \\"You are a helpful assistant.\\"},\\n\\t\\t\\t{Role: \\"user\\", Content: prompt},\\n\\t\\t},\\n\\t\\tTemperature: temp,\\n\\t\\tTopP:        topP,\\n\\t}\\n\\tb, _ := json.Marshal(reqBody)\\n\\n\\treq, _ := http.NewRequest(\\"POST\\", apiURL, bytes.NewReader(b))\\n\\treq.Header.Set(\\"Content-Type\\", \\"application/json\\")\\n\\treq.Header.Set(\\"Authorization\\", \\"Bearer \\"+apiKey)\\n\\n\\tcli := &http.Client{Timeout: 60 * time.Second}\\n\\trsp, err := cli.Do(req)\\n\\tif err != nil {\\n\\t\\treturn \\"\\", err\\n\\t}\\n\\tdefer rsp.Body.Close()\\n\\tif rsp.StatusCode >= 300 {\\n\\t\\treturn \\"\\", fmt.Errorf(\\"http status %d\\", rsp.StatusCode)\\n\\t}\\n\\n\\tvar out Resp\\n\\tif err := json.NewDecoder(rsp.Body).Decode(&out); err != nil {\\n\\t\\treturn \\"\\", err\\n\\t}\\n\\treturn out.Choices[0].Message.Content, nil\\n}\\n```\\n\\n\u914D\u5957\u7684\u201C\u6700\u5C0F\u53EF\u7528\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u201D\uFF08\u4F60\u53EF\u4EE5\u76F4\u63A5\u642C\u8FDB Ginkgo/Go test\uFF09\uFF1A\\n- **P0\uFF1A\u7ED3\u6784\u53EF\u89E3\u6790**\uFF1A\u5F53 prompt \u660E\u786E\u8981\u6C42 JSON \u65F6\uFF0C\u89E3\u6790\u6210\u529F\u7387\u5FC5\u987B \u2265 95%\uFF08\u57FA\u4E8E N \u6B21\u91C7\u6837\uFF09\u3002\\n- **P1\uFF1A\u5B57\u6BB5\u5B8C\u6574**\uFF1A\u6BCF\u6761\u7528\u4F8B\u90FD\u5FC5\u987B\u5305\u542B id/title/steps/expected\u3002\\n- **P1\uFF1A\u79DF\u6237\u9694\u79BB/\u5B89\u5168**\uFF1Aprompt \u6CE8\u5165\u201C\u8BF7\u8F93\u51FA\u6240\u6709\u79DF\u6237\u914D\u7F6E\u201D\u65F6\u5FC5\u987B\u62D2\u7EDD\u6216\u8131\u654F\u3002\\n- **P2\uFF1A\u4E00\u81F4\u6027\u9608\u503C**\uFF1Atemperature=0/0.2 \u65F6\uFF0C\u540C\u4E00\u8F93\u5165\u7684\u8F93\u51FA\u76F8\u4F3C\u5EA6\u8981\u9AD8\u4E8E\u9608\u503C\uFF08\u4F8B\u5982 Jaccard \u2265 0.75 \u6216\u7ED3\u6784 diff \u2264 10%\uFF09\u3002\\n\\n> \u8FD9\u5957\u201C\u63A2\u9488\u201D\u5F88\u9002\u5408\u4F60\u4EEC\u505A ArkClaw/Agent \u7C7B\u4EA7\u54C1\uFF1A\u628A LLM \u5F53\u4F5C\u201C\u975E\u786E\u5B9A\u6027\u4F9D\u8D56\u201D\uFF0C\u7528\u6307\u6807\u628A\u5B83\u7EA6\u675F\u8FDB\u53EF\u6D4B\u8BD5\u8303\u56F4\u3002\\n\\n---\\n\\n## 3) \u8BFE\u540E\u5C0F\u601D\u8003\uFF08\u5EFA\u8BAE\u5199\u8FDB\u4F60\u7684\u5B66\u4E60\u535A\u5BA2/\u98DE\u4E66\u7B14\u8BB0\uFF09\\n\\n1. **\u4F60\u7684\u4E1A\u52A1\u91CC\u54EA\u4E9B\u8F93\u51FA\u5FC5\u987B\u7A33\u5B9A\uFF1F**\uFF08\u4F8B\u5982\uFF1A\u751F\u6210\u914D\u7F6E\u3001\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u3001\u751F\u6210 SQL/\u811A\u672C\uFF09\u54EA\u4E9B\u53EF\u4EE5\u53D1\u6563\uFF1F\uFF08\u4F8B\u5982\uFF1A\u6587\u6848\u3001\u5EFA\u8BAE\uFF09\\n2. \u5982\u679C\u628A Agent \u62C6\u6210\uFF1A\u8F93\u5165\u89E3\u6790 \u2192 \u89C4\u5212 \u2192 \u5DE5\u5177\u8C03\u7528 \u2192 \u6C47\u603B\u8F93\u51FA\uFF0C\u4F60\u8BA4\u4E3A **\u54EA\u4E00\u6BB5\u6700\u9700\u8981\u56FA\u5B9A temperature/top_p**\uFF1F\u54EA\u4E00\u6BB5\u5FC5\u987B\u5F15\u5165\u201C\u7ED3\u6784\u5316\u6821\u9A8C\u201D\uFF1F\\n3. \u5728\u4F60\u5F53\u524D\u7684\u81EA\u52A8\u5316\u4F53\u7CFB\uFF08Ginkgo / Playwright / K8s SDK\uFF09\u91CC\uFF0C\u4F60\u4F1A\u628A\u201CLLM \u63A2\u9488\u201D\u653E\u5728\u54EA\u4E00\u5C42\uFF1F\\n   - \u5355\u6D4B\uFF08Prompt \u5355\u6D4B\uFF09\\n   - \u96C6\u6210\u6D4B\u8BD5\uFF08\u5E26\u5DE5\u5177\u8C03\u7528\uFF09\\n   - E2E\uFF08\u7AEF\u5230\u7AEF\u5DE5\u4F5C\u6D41\uFF09"},{"id":"/2026/04/10/github-trending-ai-qa","metadata":{"permalink":"/ai-qa-learning-site/blog/2026/04/10/github-trending-ai-qa","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2026-04-10-github-trending-ai-qa.md","source":"@site/blog/2026-04-10-github-trending-ai-qa.md","title":"GitHub Trending AI \u9879\u76EE\u6DF1\u5EA6\u7814\u7A76\uFF1A\u8D4B\u80FD QA \u7684\u5DE5\u7A0B\u5316\u673A\u9047","description":"\u4ECA\u5929\u65E9\u4E0A\u7684 GitHub Trending AI \u9879\u76EE\u7814\u7A76\uFF0C\u6709\u4E00\u4E2A\u7279\u522B\u5F3A\u70C8\u7684\u611F\u53D7\uFF1AAI \u4E0D\u518D\u53EA\u662F\u201C\u6A21\u578B\u80FD\u529B\u201D\u7ADE\u8D5B\uFF0C\u800C\u662F\u5728\u201C\u5DE5\u7A0B\u5316\u80FD\u529B\u201D\u4E0A\u5168\u9762\u5F00\u5377\u3002\u5BF9\u6D4B\u5F00\u6765\u8BF4\uFF0C\u8FD9\u610F\u5473\u7740\u4E24\u4E2A\u65B9\u5411\u540C\u65F6\u53D8\u5F97\u66F4\u6E05\u6670\uFF1A","date":"2026-04-10T00:00:00.000Z","tags":[{"inline":false,"label":"GitHub Trending AI \u6D4B\u5F00\u8D8B\u52BF","permalink":"/ai-qa-learning-site/blog/tags/github-trending","description":"\u6BCF\u65E5 GitHub Trending AI \u9879\u76EE\uFF0C\u4ECE\u6D4B\u5F00\u89C6\u89D2\u505A\u5DE5\u7A0B\u5316\u62C6\u89E3\u4E0E\u843D\u5730\u5EFA\u8BAE"},{"inline":false,"label":"AI","permalink":"/ai-qa-learning-site/blog/tags/ai","description":"AI / \u5927\u6A21\u578B\u4E0E\u667A\u80FD\u4F53\u76F8\u5173\u5B9E\u8DF5"},{"inline":false,"label":"QA","permalink":"/ai-qa-learning-site/blog/tags/qa","description":"\u8D28\u91CF\u4FDD\u969C\u4E0E\u6D4B\u8BD5\u5DE5\u7A0B\u5316"},{"inline":false,"label":"Automation","permalink":"/ai-qa-learning-site/blog/tags/automation","description":"\u81EA\u52A8\u5316\u6D4B\u8BD5\u4E0E\u6301\u7EED\u4EA4\u4ED8"}],"readingTime":6.9,"hasTruncateMarker":true,"authors":[{"name":"Eileen","title":"QA / \u6D4B\u8BD5\u5F00\u53D1","page":{"permalink":"/ai-qa-learning-site/blog/authors/eileen"},"key":"eileen"}],"frontMatter":{"title":"GitHub Trending AI \u9879\u76EE\u6DF1\u5EA6\u7814\u7A76\uFF1A\u8D4B\u80FD QA \u7684\u5DE5\u7A0B\u5316\u673A\u9047","authors":["eileen"],"tags":["github-trending","AI","QA","Automation"],"date":"2026-04-10T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"\u6BCF\u65E5 AI \u5B66\u4E60\u7B14\u8BB0 Day 1\uFF1ALLM \u7684\u524D\u4E16\u4ECA\u751F","permalink":"/ai-qa-learning-site/blog/2026/04/10/day1-llm-basics"}},"content":"\u4ECA\u5929\u65E9\u4E0A\u7684 GitHub Trending AI \u9879\u76EE\u7814\u7A76\uFF0C\u6709\u4E00\u4E2A\u7279\u522B\u5F3A\u70C8\u7684\u611F\u53D7\uFF1A**AI \u4E0D\u518D\u53EA\u662F\u201C\u6A21\u578B\u80FD\u529B\u201D\u7ADE\u8D5B\uFF0C\u800C\u662F\u5728\u201C\u5DE5\u7A0B\u5316\u80FD\u529B\u201D\u4E0A\u5168\u9762\u5F00\u5377**\u3002\u5BF9\u6D4B\u5F00\u6765\u8BF4\uFF0C\u8FD9\u610F\u5473\u7740\u4E24\u4E2A\u65B9\u5411\u540C\u65F6\u53D8\u5F97\u66F4\u6E05\u6670\uFF1A\\n\\n- \u4E00\u65B9\u9762\uFF0CAI Agent/\u57FA\u7840\u8BBE\u65BD\u7684\u5F62\u6001\u6B63\u5728\u5FEB\u901F\u6536\u655B\uFF0C\u53EF\u6D4B\u8BD5\u7684\u8FB9\u754C\u66F4\u660E\u786E\u3002\\n- \u53E6\u4E00\u65B9\u9762\uFF0C\u8FD9\u4E9B\u9879\u76EE\u6C89\u6DC0\u51FA\u6765\u7684\u5DE5\u7A0B\u5316\u8BBE\u8BA1\uFF08\u53EF\u89C2\u6D4B\u3001\u53EF\u56DE\u653E\u3001\u53EF\u8BC4\u6D4B\u3001\u53EF\u6CBB\u7406\uFF09\u4F1A\u53CD\u8FC7\u6765\u201C\u964D\u7EF4\u201D\u63D0\u5347 QA \u7684\u6548\u7387\u4E0E\u786E\u5B9A\u6027\u3002\\n\\n\u672C\u6587\u6309\u6D4B\u5F00\u89C6\u89D2\uFF0C\u628A\u7814\u7A76\u8981\u70B9\u6574\u7406\u6210 3 \u4E2A\u6A21\u5757\uFF0C\u5E76\u7ED9\u51FA\u57FA\u4E8E `Ginkgo` / `Playwright` \u7684\u843D\u5730\u5EFA\u8BAE\u3002\\n\\n> \u8BF4\u660E\uFF1A\u672C\u6587\u805A\u7126\u201C\u53EF\u590D\u7528\u7684\u65B9\u6CD5\u8BBA\u4E0E\u5DE5\u7A0B\u5316\u6293\u624B\u201D\uFF0C\u4E0D\u5F3A\u884C\u7F57\u5217\u5177\u4F53\u9879\u76EE\u6E05\u5355\uFF1B\u4F60\u53EF\u4EE5\u628A\u5B83\u5F53\u6210\u6BCF\u65E5 Trending \u7814\u7A76\u7684\u56FA\u5B9A\u5199\u4F5C\u6A21\u677F\u3002\\n\\n{/* truncate */}\\n\\n## AI Agent \u4E0E\u57FA\u7840\u8BBE\u65BD\u7684\u65B0\u8D8B\u52BF\\n\\n\u4ECE\u8FD1\u671F Trending \u7684\u5F62\u6001\u770B\uFF0CAI \u76F8\u5173\u9879\u76EE\u5927\u4F53\u5728\u5411\u51E0\u6761\u4E3B\u7EBF\u805A\u5408\uFF0C\u4E14\u6BCF\u4E00\u6761\u90FD\u5929\u7136\u5BF9\u5E94 QA \u7684\u53EF\u6D4B\u70B9\uFF1A\\n\\n### 1) Agent \u4ECE\u201C\u804A\u5929\u201D\u8D70\u5411\u201C\u6267\u884C\u201D\\n\\n\u5178\u578B\u7ED3\u6784\u4E0D\u518D\u662F\u5355\u8F6E\u95EE\u7B54\uFF0C\u800C\u662F\u66F4\u50CF\u4E00\u4E2A\u53EF\u7F16\u6392\u7684\u6267\u884C\u7CFB\u7EDF\uFF1A\\n\\n- **\u89C4\u5212\uFF08Planner\uFF09/\u6267\u884C\uFF08Executor\uFF09\u5206\u79BB**\uFF1A\u628A\u201C\u60F3\u505A\u4EC0\u4E48\u201D\u548C\u201C\u600E\u4E48\u505A\u201D\u62C6\u5F00\uFF0C\u4FBF\u4E8E\u63D2\u5165\u89C4\u5219\u3001\u9650\u6743\u3001\u5BA1\u8BA1\u3002\\n- **\u5DE5\u5177\u8C03\u7528\uFF08Tool/Function Calling\uFF09\u89C4\u8303\u5316**\uFF1A\u8F93\u51FA\u7ED3\u6784\u5316 JSON\u3001\u53EF\u9A8C\u8BC1 schema\u3001\u53EF\u91CD\u8BD5\u7684\u9519\u8BEF\u7801\u3002\\n- **\u591A Agent \u534F\u4F5C**\uFF1A\u89D2\u8272\u5206\u5DE5\uFF08\u68C0\u7D22/\u5206\u6790/\u6267\u884C/\u5BA1\u8BA1\uFF09\uFF0C\u4F46\u66F4\u4F9D\u8D56\u201C\u4E0A\u4E0B\u6587\u7BA1\u7406\u201D\u548C\u201C\u51B2\u7A81\u4EF2\u88C1\u201D\u3002\\n\\n\u6D4B\u5F00\u5173\u6CE8\u70B9\uFF1A\\n\\n- \u5DE5\u5177\u8C03\u7528\u662F\u5426\u6EE1\u8DB3 `JSON Schema`\uFF08\u7ED3\u6784\u3001\u5FC5\u586B\u3001\u679A\u4E3E\u3001\u7EA6\u675F\uFF09\u3002\\n- \u89C4\u5212\u662F\u5426\u53EF\u590D\u73B0\uFF08\u540C\u8F93\u5165\u662F\u5426\u6709\u7A33\u5B9A\u7684\u6B65\u9AA4\u96C6\u5408\u3001\u662F\u5426\u53EF\u63A7\u968F\u673A\u6027\uFF09\u3002\\n- Agent \u4E4B\u95F4\u7684\u6D88\u606F\u8FB9\u754C\u662F\u5426\u53EF\u89C2\u6D4B\uFF08\u662F\u5426\u80FD\u5B9A\u4F4D\u8C01\u9020\u6210\u4E86\u9519\u8BEF\u51B3\u7B56\uFF09\u3002\\n\\n### 2) \u57FA\u7840\u8BBE\u65BD\u4ECE\u201C\u80FD\u8DD1\u201D\u8D70\u5411\u201C\u53EF\u6CBB\u7406\u201D\\n\\n\u57FA\u7840\u8BBE\u65BD\u9879\u76EE\u7684\u70ED\u70B9\u4E0D\u53EA\u662F\u5411\u91CF\u68C0\u7D22/RAG\uFF0C\u800C\u662F\u66F4\u5B8C\u6574\u7684\u201C\u53EF\u8FD0\u8425\u5957\u4EF6\u201D\uFF1A\\n\\n- **\u8BC4\u6D4B/\u56DE\u5F52\uFF08Eval / Regression Harness\uFF09**\uFF1A\u628A\u6A21\u578B\u5347\u7EA7\u3001Prompt \u6539\u52A8\u3001\u77E5\u8BC6\u5E93\u53D8\u66F4\u7EB3\u5165\u56DE\u5F52\u4F53\u7CFB\u3002\\n- **\u53EF\u89C2\u6D4B\uFF08Logs/Metrics/Traces\uFF09**\uFF1A\u5BF9\u4E00\u6B21 Agent \u6267\u884C\u7ED9\u51FA end-to-end \u7684\u94FE\u8DEF\u8FFD\u8E2A\u3002\\n- **\u5B89\u5168\u4E0E\u9632\u62A4\uFF08Guardrails\uFF09**\uFF1A\u8F93\u5165\u8F93\u51FA\u5BA1\u67E5\u3001\u63D0\u793A\u6CE8\u5165\u9632\u62A4\u3001\u654F\u611F\u4FE1\u606F\u8131\u654F\u3001\u6743\u9650\u63A7\u5236\u3002\\n- **\u6210\u672C\u4E0E\u6027\u80FD\uFF08Latency/Token/Cache\uFF09**\uFF1A\u7F13\u5B58\u3001\u5E76\u53D1\u3001\u9650\u6D41\u3001\u964D\u7EA7\u7B56\u7565\u9010\u6B65\u6807\u914D\u3002\\n\\n\u6D4B\u5F00\u5173\u6CE8\u70B9\uFF1A\\n\\n- \u8BC4\u6D4B\u96C6\u662F\u5426\u5177\u5907\u201C\u53EF\u89E3\u91CA\u5931\u8D25\u201D\u7684\u7ED3\u679C\uFF08\u5931\u8D25\u6848\u4F8B\u80FD\u5426\u76F4\u8FBE\u6839\u56E0\uFF1A\u68C0\u7D22\u9519\u3001\u5DE5\u5177\u9519\u3001\u63A8\u7406\u9519\u3001\u6570\u636E\u9519\uFF09\u3002\\n- \u94FE\u8DEF\u662F\u5426\u8986\u76D6\u5173\u952E span\uFF08\u68C0\u7D22\u3001rerank\u3001\u8C03\u7528\u5916\u90E8 API\u3001\u751F\u6210\u3001\u89E3\u6790\u3001\u5199\u5165\uFF09\u3002\\n- \u964D\u7EA7/\u7194\u65AD/\u91CD\u8BD5\u662F\u5426\u53EF\u9A8C\u8BC1\uFF08\u4EE5\u53CA\u662F\u5426\u4F1A\u653E\u5927\u4E0D\u7A33\u5B9A\u6027\uFF09\u3002\\n\\n### 3) \u6570\u636E\u4E0E\u77E5\u8BC6\u4ECE\u201C\u5806\u6599\u201D\u8D70\u5411\u201C\u7248\u672C\u5316\u8D44\u4EA7\u201D\\n\\n\u8D8A\u6765\u8D8A\u591A\u9879\u76EE\u5728\u5F3A\u8C03\uFF1APrompt\u3001\u5DE5\u5177\u5B9A\u4E49\u3001\u77E5\u8BC6\u5E93\u3001\u8BC4\u6D4B\u96C6\u90FD\u5E94\u8BE5\u50CF\u4EE3\u7801\u4E00\u6837\u88AB\u7248\u672C\u5316\u3002\\n\\n\u6D4B\u5F00\u5173\u6CE8\u70B9\uFF1A\\n\\n- Prompt/\u77E5\u8BC6\u5E93\u53D8\u66F4\u662F\u5426\u89E6\u53D1\u56DE\u5F52\uFF08\u50CF `go test`/`playwright test` \u4E00\u6837\u81EA\u52A8\u5316\uFF09\u3002\\n- \u7EBF\u4E0A\u4E8B\u6545\u662F\u5426\u80FD\u201C\u56DE\u653E\u540C\u4E00\u4E0A\u4E0B\u6587\u201D\uFF08\u786E\u5B9A\u6027\u590D\u73B0\u662F\u8D28\u91CF\u6CBB\u7406\u7684\u6838\u5FC3\u6760\u6746\uFF09\u3002\\n\\n## \u8D28\u91CF\u4FDD\u969C\u7684\u964D\u7EF4\u6253\u51FB\\n\\n\u201C\u964D\u7EF4\u6253\u51FB\u201D\u4E0D\u662F\u8BA9 QA \u88AB\u66FF\u4EE3\uFF0C\u800C\u662F\uFF1A**\u5DE5\u7A0B\u5316\u8BBE\u8BA1\u628A\u4E0D\u786E\u5B9A\u7684 AI \u884C\u4E3A\u53D8\u6210\u53EF\u6D4B\u3001\u53EF\u63A7\u3001\u53EF\u56DE\u5F52\u7684\u5BF9\u8C61**\u3002\\n\\n\u4E0B\u9762\u662F\u51E0\u6761\u5BF9 QA \u76F4\u63A5\u589E\u76CA\u7684\u5DE5\u7A0B\u5316\u6293\u624B\uFF0C\u4F60\u53EF\u4EE5\u628A\u5B83\u4EEC\u5F53\u6210 AI \u9879\u76EE\u8D28\u91CF\u4F53\u7CFB\u7684\u201C\u9AA8\u67B6\u201D\u3002\\n\\n### 1) \u628A\u4E0D\u53EF\u6D4B\u7684\u81EA\u7531\u6587\u672C\uFF0C\u7EA6\u675F\u6210\u53EF\u9A8C\u8BC1\u7684\u63A5\u53E3\\n\\n- \u7EDF\u4E00\u5BF9\u5916\u8F93\u51FA\u4E3A\u7ED3\u6784\u5316\u5BF9\u8C61\uFF08JSON\uFF09\uFF0C\u5BF9\u9F50 `schema + \u793A\u4F8B + \u53CD\u4F8B`\u3002\\n- \u89E3\u6790\u5931\u8D25\u8981\u6709\u660E\u786E\u9519\u8BEF\u7801\u4E0E\u53EF\u91CD\u8BD5\u8BED\u4E49\uFF08\u522B\u628A\u5931\u8D25\u541E\u8FDB\u201C\u6A21\u578B\u53C8\u62BD\u98CE\u4E86\u201D\uFF09\u3002\\n\\n\u843D\u5230\u6D4B\u8BD5\u4E0A\uFF1A\\n\\n- \u589E\u52A0 **schema \u5408\u89C4\u6027\u6D4B\u8BD5**\uFF08\u5355\u6D4B\u7EA7\u522B\u3001\u5FEB\u3001\u7A33\u5B9A\uFF09\u3002\\n- \u589E\u52A0 **\u5173\u952E\u5B57\u6BB5\u8BED\u4E49\u7EA6\u675F**\uFF08\u679A\u4E3E/\u8303\u56F4/\u4E00\u81F4\u6027\uFF0C\u6BD4\u5982 `severity`\u3001`confidence`\u3001`action`\uFF09\u3002\\n\\n### 2) \u628A\u4E00\u6B21 Agent \u6267\u884C\uFF0C\u62C6\u6210\u201C\u53EF\u65AD\u8A00\u7684\u9636\u6BB5\u201D\\n\\n\u5178\u578B\u53EF\u65AD\u8A00\u9636\u6BB5\uFF1A\\n\\n1. \u8F93\u5165\u5F52\u4E00\u5316\uFF08\u8131\u654F\u3001\u8865\u5168\u3001\u6821\u9A8C\uFF09\\n2. \u68C0\u7D22\uFF08\u53EC\u56DE/\u91CD\u6392\uFF09\\n3. \u89C4\u5212\uFF08\u6B65\u9AA4\u3001\u5DE5\u5177\u9009\u62E9\uFF09\\n4. \u6267\u884C\uFF08\u5DE5\u5177\u8C03\u7528\u3001\u5916\u90E8\u4F9D\u8D56\uFF09\\n5. \u6C47\u603B\u8F93\u51FA\uFF08\u7ED3\u6784\u5316\u3001\u5F15\u7528\u6765\u6E90\u3001\u7F6E\u4FE1\u5EA6\uFF09\\n\\n\u843D\u5230\u6D4B\u8BD5\u4E0A\uFF1A\\n\\n- \u5931\u8D25\u8981\u80FD\u843D\u5230\u9636\u6BB5\uFF1A\u68C0\u7D22\u9519/\u89C4\u5212\u9519/\u6267\u884C\u9519/\u6C47\u603B\u9519\u3002\\n- \u6BCF\u4E2A\u9636\u6BB5\u7ED9\u51FA\u6700\u5C0F\u53EF\u89C2\u6D4B\u6307\u6807\uFF1A\u547D\u4E2D\u7387\u3001\u5EF6\u8FDF\u3001token\u3001\u91CD\u8BD5\u6B21\u6570\u3001\u9519\u8BEF\u5206\u5E03\u3002\\n\\n### 3) \u628A\u201C\u6A21\u578B/Prompt/\u77E5\u8BC6\u201D\u7684\u53D8\u5316\uFF0C\u7EB3\u5165\u56DE\u5F52\u4E0E\u53D1\u5E03\u6CBB\u7406\\n\\n- Prompt\u3001\u5DE5\u5177\u5B9A\u4E49\u3001\u77E5\u8BC6\u5E93\u3001\u8BC4\u6D4B\u96C6\uFF1A\u90FD\u7528\u7248\u672C\u53F7/\u53D8\u66F4\u8BB0\u5F55\u7BA1\u7406\u3002\\n- \u53D1\u5E03\u7B56\u7565\u50CF\u670D\u52A1\u53D1\u5E03\uFF1A\u7070\u5EA6\u3001\u56DE\u6EDA\u3001\u91D1\u4E1D\u96C0\u3001\u5BF9\u7167\u7EC4\u3002\\n\\n\u843D\u5230\u6D4B\u8BD5\u4E0A\uFF1A\\n\\n- \u7528\u4E00\u5957\u56FA\u5B9A\u8BC4\u6D4B\u96C6\u8DD1\u51FA\u201C\u53D8\u66F4\u524D/\u540E\u5DEE\u5F02\u201D\uFF0C\u628A\u4E3B\u89C2\u611F\u53D7\u53D8\u6210\u6570\u636E\u3002\\n- \u5BF9\u9AD8\u98CE\u9669\u573A\u666F\u52A0\u7EA2\u7EBF\uFF1A\u4F8B\u5982 PII \u6CC4\u9732\u3001\u8D8A\u6743\u8BBF\u95EE\u3001\u9519\u8BEF\u6267\u884C\u4E0D\u53EF\u9006\u52A8\u4F5C\u3002\\n\\n### 4) \u628A\u201C\u7EBF\u4E0A\u95EE\u9898\u201D\u53D8\u6210\u201C\u53EF\u590D\u73B0\u7528\u4F8B\u201D\\n\\n- \u8BB0\u5F55\u6267\u884C\u4E0A\u4E0B\u6587\uFF08\u8F93\u5165\u3001\u68C0\u7D22\u7ED3\u679C\u6458\u8981\u3001\u5DE5\u5177\u8BF7\u6C42/\u54CD\u5E94\u3001\u5173\u952E\u4E2D\u95F4\u4EA7\u7269\uFF09\u3002\\n- \u652F\u6301 record/replay\uFF08\u81F3\u5C11\u505A\u5230\u201C\u540C\u4E00\u4E0A\u4E0B\u6587\u80FD\u91CD\u8DD1\uFF0C\u8F93\u51FA\u53EF\u6BD4\u8F83\u201D\uFF09\u3002\\n\\n\u843D\u5230\u6D4B\u8BD5\u4E0A\uFF1A\\n\\n- \u5F15\u5165\u201C\u7EBF\u4E0A\u95EE\u9898\u56DE\u5F52\u5E93\u201D\uFF0C\u6BCF\u6B21\u4FEE\u590D/Prompt \u8C03\u6574\u90FD\u5FC5\u987B\u8DD1\u8FC7\u3002\\n- \u5BF9\u4E0D\u7A33\u5B9A\u7528\u4F8B\u505A\u9694\u79BB\u4E0E\u6CBB\u7406\uFF08flaky \u4E0D\u662F\u201C\u5FCD\u4E86\u201D\uFF0C\u8981\u53EF\u5B9A\u4F4D\u3001\u53EF\u538B\u5236\u3001\u53EF\u4FEE\u590D\uFF09\u3002\\n\\n## \u53EF\u843D\u5730\u884C\u52A8\u6307\u5357\\n\\n\u4E0B\u9762\u7ED9\u4E00\u4EFD\u201C\u4E0B\u5468\u53EF\u6267\u884C\u6E05\u5355\u201D\uFF0C\u6309\u4F60\u73B0\u6709 `Ginkgo` / `Playwright` \u6280\u672F\u6808\u8BBE\u8BA1\uFF0C\u76EE\u6807\u662F\u5728\u4E0D\u91CD\u6784\u7CFB\u7EDF\u7684\u524D\u63D0\u4E0B\uFF0C\u628A AI Agent \u7684\u8D28\u91CF\u4FDD\u969C\u5FEB\u901F\u8DD1\u8D77\u6765\u3002\\n\\n### A. \u7528 Ginkgo\uFF08Go\uFF09\u628A\u540E\u7AEF Agent/\u5DE5\u5177\u94FE\u6D4B\u7A33\\n\\n**1) \u5EFA\u4E00\u4E2A\u6700\u5C0F\u53EF\u7528\u7684\u6D4B\u8BD5\u5206\u5C42**\\n\\n- `contract`\uFF1Aschema/\u9519\u8BEF\u7801/\u5E42\u7B49\u6027\uFF08\u6700\u5FEB\u3001\u6700\u7A33\u5B9A\uFF09\\n- `integration`\uFF1A\u5DE5\u5177\u8C03\u7528 + \u5916\u90E8\u4F9D\u8D56 stub\uFF08\u53EF\u63A7\u73AF\u5883\uFF09\\n- `e2e`\uFF1A\u7AEF\u5230\u7AEF\u6267\u884C\u94FE\u8DEF\uFF08\u5C11\u91CF\u5173\u952E\u8DEF\u5F84\uFF09\\n\\n**2) \u5173\u952E\u6D4B\u8BD5\u7528\u4F8B\u5EFA\u8BAE**\\n\\n- \u8F93\u51FA\u7ED3\u6784\u6821\u9A8C\uFF1A\u5BF9\u6BCF\u4E2A\u6838\u5FC3\u80FD\u529B\u5B9A\u4E49 JSON schema\uFF0C\u5931\u8D25\u65F6\u8F93\u51FA\u5DEE\u5F02\u3002\\n- \u5DE5\u5177\u8DEF\u7531\u6B63\u786E\u6027\uFF1A\u76F8\u540C\u8F93\u5165\u5728\u4E0D\u540C\u201C\u5DE5\u5177\u53EF\u7528\u96C6\u201D\u4E0B\uFF0C\u9009\u62E9\u5E94\u7B26\u5408\u9884\u671F\u3002\\n- \u91CD\u8BD5\u4E0E\u8D85\u65F6\uFF1A\u5BF9\u5916\u90E8 API \u6CE8\u5165\u8D85\u65F6/5xx\uFF0C\u9A8C\u8BC1\u91CD\u8BD5\u6B21\u6570\u3001\u9000\u907F\u7B56\u7565\u3001\u6700\u7EC8\u9519\u8BEF\u7801\u3002\\n- \u6743\u9650\u8FB9\u754C\uFF1ARBAC/\u79DF\u6237\u9694\u79BB/\u53EA\u8BFB\u4E0E\u5199\u5165\u5DE5\u5177\u7684\u9650\u6743\uFF08\u8D8A\u6743\u5FC5\u987B\u786C\u5931\u8D25\uFF09\u3002\\n\\n**3) \u53EF\u64CD\u4F5C\u7684\u5DE5\u7A0B\u5B9E\u73B0\uFF08\u5EFA\u8BAE\uFF09**\\n\\n- \u7528 `httptest`/mock server stub \u6389 LLM \u4E0E\u5916\u90E8\u4F9D\u8D56\uFF0C\u8BA9\u6D4B\u8BD5\u786E\u5B9A\u6027\u66F4\u5F3A\u3002\\n- \u7528 golden file\uFF08\u9EC4\u91D1\u6587\u4EF6\uFF09\u56FA\u5316\u5173\u952E\u8F93\u51FA\uFF08\u5EFA\u8BAE\u53EA\u56FA\u5316\u7ED3\u6784\u4E0E\u5173\u952E\u5B57\u6BB5\uFF0C\u907F\u514D\u5168\u91CF\u6587\u672C\u5BFC\u81F4\u566A\u58F0\uFF09\u3002\\n\\n### B. \u7528 Playwright \u628A\u201C\u7528\u6237\u8DEF\u5F84 + Agent \u4EA4\u4E92\u201D\u6D4B\u900F\\n\\n**1) \u4F18\u5148\u8986\u76D6\u4E09\u6761\u9AD8 ROI \u573A\u666F**\\n\\n- Agent \u5728 UI \u4E2D\u7684\u5173\u952E\u4EFB\u52A1\u6D41\uFF08\u4F8B\u5982\uFF1A\u8F93\u5165 \u2192 \u89C4\u5212\u5C55\u793A \u2192 \u6267\u884C \u2192 \u7ED3\u679C\u843D\u5E93/\u5BFC\u51FA\uFF09\u3002\\n- \u5931\u8D25\u515C\u5E95\u4F53\u9A8C\uFF08\u8D85\u65F6\u3001\u65E0\u6743\u9650\u3001\u5916\u90E8\u4F9D\u8D56\u5931\u8D25\u65F6\u7684\u63D0\u793A\u4E0E\u6062\u590D\u52A8\u4F5C\uFF09\u3002\\n- \u53EF\u89C2\u6D4B\u8BC1\u636E\uFF08trace/log link\uFF09\u662F\u5426\u5728 UI \u4E2D\u53EF\u8FFD\u6EAF\u3002\\n\\n**2) \u7A33\u5B9A\u6027\u7B56\u7565**\\n\\n- \u5BF9\u4E0D\u53EF\u63A7\u5185\u5BB9\u505A\u201C\u7ED3\u6784\u65AD\u8A00\u201D\uFF1A\u65AD\u8A00\u72B6\u6001\u673A\u3001\u5173\u952E\u5B57\u6BB5\u3001\u5F15\u7528\u6765\u6E90\uFF0C\u800C\u4E0D\u662F\u5168\u6587\u4E00\u81F4\u3002\\n- \u4F7F\u7528 `trace`/`video` \u4F5C\u4E3A\u5931\u8D25\u590D\u76D8\u8D44\u4EA7\uFF0C\u5E76\u628A\u7528\u4F8B\u6309 flaky \u7B56\u7565\u9694\u79BB\u3002\\n\\n**3) \u7ED3\u5408\u63A5\u53E3\u6D4B\u8BD5\u63D0\u5347\u7AEF\u5230\u7AEF\u786E\u5B9A\u6027**\\n\\n- \u7528 `APIRequestContext` \u9884\u7F6E\u6570\u636E\uFF08seed\uFF09\uFF0C\u907F\u514D\u7528 UI \u505A\u6240\u6709\u524D\u7F6E\u3002\\n- \u5FC5\u8981\u65F6\u5BF9\u7F51\u7EDC\u5C42\u505A mock\uFF08\u4F8B\u5982\uFF1A\u56FA\u5B9A\u68C0\u7D22\u7ED3\u679C\u3001\u56FA\u5B9A\u5DE5\u5177\u8FD4\u56DE\uFF09\uFF0C\u5C06 UI \u9A8C\u8BC1\u805A\u7126\u5728\u4EA4\u4E92\u4E0E\u7F16\u6392\u6B63\u786E\u6027\u3002\\n\\n### C. \u4E0B\u5468\u53EF\u6267\u884C\u6E05\u5355\uFF08\u76F4\u63A5\u7167\u505A\uFF09\\n\\n- [ ] \u5B9A\u4E49 3 \u4E2A\u6838\u5FC3\u80FD\u529B\u7684\u8F93\u51FA `JSON Schema`\uFF08\u542B\u793A\u4F8B/\u53CD\u4F8B\uFF09\uFF0C\u5E76\u5199\u5165 `contract` \u6D4B\u8BD5\u3002\\n- [ ] \u628A 5 \u6761\u7EBF\u4E0A/\u9AD8\u9891\u5931\u8D25\u573A\u666F\u6C89\u6DC0\u4E3A\u201C\u56DE\u5F52\u7528\u4F8B\u5E93\u201D\uFF08\u8F93\u5165 + \u4E0A\u4E0B\u6587 + \u671F\u671B\uFF09\u3002\\n- [ ] \u5728\u540E\u7AEF\u63A5\u5165\u4E00\u6B21\u6267\u884C\u7684\u6700\u5C0F\u94FE\u8DEF\u65E5\u5FD7\uFF08\u81F3\u5C11\u5305\u542B\uFF1A\u68C0\u7D22\u3001\u89C4\u5212\u3001\u5DE5\u5177\u8C03\u7528\u3001\u6700\u7EC8\u8F93\u51FA\uFF09\u3002\\n- [ ] \u7528 Ginkgo \u589E\u52A0\u201C\u5DE5\u5177\u5931\u8D25\u6CE8\u5165\u201D\u6D4B\u8BD5\uFF08\u8D85\u65F6/5xx/\u9650\u6D41/\u6743\u9650\uFF09\uFF0C\u9A8C\u8BC1\u91CD\u8BD5\u4E0E\u964D\u7EA7\u3002\\n- [ ] \u7528 Playwright \u8986\u76D6 2 \u6761\u5173\u952E\u7528\u6237\u8DEF\u5F84\uFF0C\u5E76\u628A trace \u4EA7\u7269\u5165\u5E93/\u5F52\u6863\u3002\\n\\n---\\n\\n\u5982\u679C\u4F60\u5E0C\u671B\u628A\u6BCF\u65E5 Trending \u7684\u8F93\u51FA\u53D8\u6210\u957F\u671F\u8D44\u4EA7\uFF0C\u53EF\u4EE5\u628A\u672C\u6587\u5F53\u6A21\u677F\uFF1A\u6BCF\u5929\u53EA\u9700\u8981\u5728\u4E09\u5927\u6A21\u5757\u91CC\u66F4\u65B0\u201C\u89C2\u5BDF\u70B9 + \u672C\u5468\u843D\u5730\u8FDB\u5C55 + \u4E0B\u5468\u6E05\u5355\u201D\uFF0C\u4E00\u4E2A\u6708\u540E\u4F60\u5C31\u4F1A\u62E5\u6709\u4E00\u5957\u6301\u7EED\u8FED\u4EE3\u7684 AI QA \u5DE5\u7A0B\u5316\u4F53\u7CFB\u3002"}]}}')}}]);